from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(
        resolve_entities=False, no_network=True, disallowed_doctypes=True
    )
    try:
        root = etree.fromstring(xml_data, parser)
    except etree.XMLSyntaxError:
        return None

    query = '//student[username[text()=$user] and password[text()=$pass]]'
    students = root.xpath(query, {"user": username, "pass": password})

    if not students:
        return None

    student = students[0]
    info = {}
    for child in student:
        info[child.tag] = child.text
    return info

